def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = float('inf')
        else:
            score = 0
            decay = 1.0
            for j in range(5):
                sqrt_term = np.sqrt(ratio + 0.1)
                if sqrt_term > 0.8:
                    score += sqrt_term * decay * (1 + 0.1*j)
                else:
                    score += sqrt_term * decay
                decay *= 0.85
                ratio *= 0.9
                if ratio < 0.005:
                    break
            if score > 2:
                priorities[i] = score * 15
            elif score > 1:
                priorities[i] = score * 8
            else:
                multip = 1
                for k in range(3):
                    multip *= (1 + 0.05*k)
                priorities[i] = score * multip * 5
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        min_priority = np.min(finite_priorities)
    else:
        min_priority = 1.0
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = min_priority * 120
        elif priorities[i] == 0:
            priorities[i] = min_priority * 2
    normalized = (priorities - np.min(priorities)) / (np.ptp(priorities) + 1e-8)
    for i in range(len(normalized)):
        if normalized[i] < 0.1:
            normalized[i] += 0.05 * i
    return normalized
